using BgCommon;using BgControls.Windows.Controls.PropertyGrid.Attributes;using BgControls.Windows.Controls.PropertyGrid.Commands;using BgControls.Windows.Controls.PropertyGrid.Editors;using System.ComponentModel.DataAnnotations;namespace BgControls.Windows.Controls.PropertyGrid;internal abstract class DescriptorPropertyDefinitionBase : DependencyObject{    public static readonly DependencyProperty AdvancedOptionsIconProperty =        DependencyProperty.Register("AdvancedOptionsIcon", typeof(ImageSource), typeof(DescriptorPropertyDefinitionBase), new UIPropertyMetadata(null));    public static readonly DependencyProperty AdvancedOptionsTooltipProperty =        DependencyProperty.Register("AdvancedOptionsTooltip", typeof(object), typeof(DescriptorPropertyDefinitionBase), new UIPropertyMetadata(null));    public static readonly DependencyProperty IsExpandableProperty =        DependencyProperty.Register("IsExpandable", typeof(bool), typeof(DescriptorPropertyDefinitionBase), new UIPropertyMetadata(false));    public static readonly DependencyProperty ValueProperty =        DependencyProperty.Register("Value", typeof(object), typeof(DescriptorPropertyDefinitionBase), new UIPropertyMetadata(null, OnValueChanged));    private string category;    private string categoryValue;    private string description;    private string displayName;    private object defaultValue;    private object definitionKey;    private IList<string> dependsOnPropertyItemNames;    private int displayOrder;    private bool expandableAttribute;    private bool expandableProperty;    private bool isReadOnly;    private IList<Type> newItemTypes;    private IEnumerable<CommandBinding> commandBindings;    private List<VisibleToAttribute>? visibleToAttributes = new List<VisibleToAttribute>();    private List<EnableToAttribute>? enableToAttributes = new List<EnableToAttribute>();    private PositionAttribute? position;    private int? decimalPlaces;    private double? increment;    private double? maximum;    private double? minimum;    internal DescriptorPropertyDefinitionBase(        bool isPropertyGridCategorized,        bool isExpandingNonPrimitiveTypes,        bool? canExpandProperty)    {        this.IsPropertyGridCategorized = isPropertyGridCategorized;        this.IsExpandingNonPrimitiveTypes = isExpandingNonPrimitiveTypes;        this.CanExpandProperty = canExpandProperty.HasValue && canExpandProperty.Value;    }    public ImageSource AdvancedOptionsIcon    {        get => (ImageSource)GetValue(AdvancedOptionsIconProperty);        set => SetValue(AdvancedOptionsIconProperty, value);    }    public object AdvancedOptionsTooltip    {        get => GetValue(AdvancedOptionsTooltipProperty);        set => SetValue(AdvancedOptionsTooltipProperty, value);    }    public bool IsExpandable    {        get => (bool)GetValue(IsExpandableProperty);        set => SetValue(IsExpandableProperty, value);    }    public object Value    {        get => this.GetValue(ValueProperty);        set => this.SetValue(ValueProperty, value);    }    public string Category    {        get => this.category;        internal set => this.category = value;    }    public string CategoryValue    {        get => this.categoryValue;        internal set => this.categoryValue = value;    }    public string DisplayName    {        get => this.displayName;        internal set => this.displayName = value;    }    public object DefaultValue    {        get => this.defaultValue;        set => this.defaultValue = value;    }    public string Description    {        get => this.description;        internal set => this.description = value;    }    public int DisplayOrder    {        get => this.displayOrder;        internal set => this.displayOrder = value;    }    internal bool ExpandableAttribute    {        get => this.expandableAttribute;        set        {            this.expandableAttribute = value;            this.UpdateIsExpandable();        }    }    internal bool ExpandableProperty    {        get => this.expandableProperty;        set        {            this.expandableProperty = value;            this.UpdateIsExpandable();        }    }    /// <summary>    /// Gets 当前对象关联的所有可见性控制特性（VisibleByAttribute）集合.    /// </summary>                                                                                              internal List<VisibleToAttribute>? VisibleToAttributes => this.visibleToAttributes;    /// <summary>    /// Gets 当前对象关联的所有可用性控制特性（EnableByAttribute）集合.    /// </summary>                                                                                             internal List<EnableToAttribute>? EnableToAttributes => this.enableToAttributes;    internal bool HasPosition => this.position != null;    /// <summary>    /// Gets 当前属性对象关联的位置信息特性.    /// </summary>                                                                       internal PositionAttribute? Position => this.position;    /// <summary>    /// Gets or sets 小数点位数.    /// </summary>                                                                     public int? DecimalPlaces    {        get => this.decimalPlaces;        set => this.decimalPlaces = value;    }    /// <summary>    /// Gets or sets 步长.    /// </summary>                                                                  public double? Increment    {        get => this.increment;        set => this.increment = value;    }    /// <summary>    /// Gets or sets 最大值.    /// </summary>                                                                   public double? Maximum    {        get => this.maximum;        set => this.maximum = value;    }    /// <summary>    /// Gets or sets 最小值.    /// </summary>                                                                   public double? Minimum    {        get => this.minimum;        set => this.minimum = value;    }    internal abstract PropertyDescriptor PropertyDescriptor { get; }    public IEnumerable<CommandBinding> CommandBindings => this.commandBindings;    public object DefinitionKey => this.definitionKey;    public IList<string> DependsOnPropertyItemNames => dependsOnPropertyItemNames;    public bool IsReadOnly => this.isReadOnly;    public IList<Type> NewItemTypes => this.newItemTypes;    public string PropertyName => this.PropertyDescriptor.Name;    public Type PropertyType => this.PropertyDescriptor.PropertyType;    internal bool IsPropertyGridCategorized { get; set; }    internal bool IsExpandingNonPrimitiveTypes { get; set; }    internal bool CanExpandProperty { get; set; }    public event EventHandler? ContainerHelperInvalidated;    protected abstract void CreateValueBinding();    internal abstract ObjectContainerHelperBase CreateContainerHelper(IPropertyContainer parent);    internal virtual ITypeEditor CreateDefaultEditor(PropertyItem propertyItem) => null;    internal virtual ITypeEditor CreateAttributeEditor() => null;    internal virtual void OnValueChanged(object oldValue, object newValue)    {        UpdateIsExpandable();        UpdateAdvanceOptions();        CommandManager.InvalidateRequerySuggested();    }    public virtual void InitProperties()    {        this.isReadOnly = this.ComputeIsReadOnly();        this.category = this.ComputeCategory();        this.categoryValue = this.ComputeCategoryValue();        this.description = this.ComputeDescription();        this.displayName = this.ComputeDisplayName();        this.defaultValue = this.ComputeDefaultValueAttribute();        this.displayOrder = this.ComputeDisplayOrder(IsPropertyGridCategorized);        this.expandableAttribute = this.ComputeExpandableAttribute();        this.definitionKey = this.ComputeDefinitionKey();        this.dependsOnPropertyItemNames = this.ComputeDependsOnPropertyItems();        this.expandableProperty = this.IsExpandingNonPrimitiveTypes ? this.CanExpandFromCollection() : CanExpandProperty;        this.newItemTypes = this.ComputeNewItemTypes();        this.visibleToAttributes = this.ComputeVisibleByAttributes();        this.enableToAttributes = this.ComputeEnableByAttributes();        this.position = this.ComputePosition();        this.ComputeNumberFormatOptions();        this.commandBindings = new CommandBinding[2]        {            new CommandBinding(PropertyItemCommands.ResetValue, ExecuteResetValueCommand, CanExecuteResetValueCommand),            new CommandBinding(PropertyItemCommands.CopyValue, ExecuteCopyValueCommand, CanExecuteCopyValueCommand),        };        this.CreateValueBinding();    }    protected virtual string ComputeCategory() => null;    protected virtual string ComputeCategoryValue() => null;    protected virtual string? ComputeDescription() => null;    protected virtual object? ComputeDefinitionKey() => null;    protected virtual IList<string>? ComputeDependsOnPropertyItems() => null;    protected virtual int ComputeDisplayOrder(bool isPropertyGridCategorized) => int.MaxValue;    protected virtual bool ComputeExpandableAttribute() => false;    protected virtual object? ComputeDefaultValueAttribute() => null;    protected abstract bool ComputeIsExpandable();    protected virtual IList<Type>? ComputeNewItemTypes() => null;    protected virtual bool ComputeIsReadOnly() => false;    protected virtual bool ComputeCanResetValue() => false;    protected virtual bool ComputeCanCopyValue() => true;    protected virtual object ComputeAdvancedOptionsTooltip() => null;    protected virtual List<VisibleToAttribute>? ComputeVisibleByAttributes()    {        return this.PropertyDescriptor.Attributes.Cast<Attribute>()                                                  .Where(a => a is VisibleToAttribute)                                                  .Select(a => (VisibleToAttribute)a)                                                  .ToList();    }    protected virtual List<EnableToAttribute> ComputeEnableByAttributes()    {        return this.PropertyDescriptor.Attributes.Cast<Attribute>()                                                  .Where(a => a is EnableToAttribute)                                                  .Select(a => (EnableToAttribute)a)                                                  .ToList();    }    protected virtual PositionAttribute? ComputePosition()    {        return this.PropertyDescriptor.GetAttribute<PositionAttribute>();    }    protected virtual void ComputeNumberFormatOptions()    {        this.DecimalPlaces = null;        this.Increment = null;        this.Maximum = null;        this.Minimum = null;        var constraint = this.PropertyDescriptor.GetAttribute<NumberPropertyConstraintAttribute>();        if (constraint != null)        {            this.DecimalPlaces = constraint.DecimalPlaces;            this.Increment = constraint.Increment;            if (constraint.Maximum != double.PositiveInfinity)            {                this.Maximum = constraint.Maximum;            }            if (constraint.Minimum != double.NegativeInfinity)            {                this.Minimum = constraint.Minimum;            }        }        else        {            if (this.PropertyType.IsNumberType())            {                if (this.PropertyType.IsFloatType(false))                {                    this.DecimalPlaces = 2;                    this.Increment = 0.01;                }                else                {                    this.DecimalPlaces = 0;                    this.Increment = 1;                }            }        }    }    protected virtual void ResetValue()    {        BindingOperations.GetBindingExpressionBase(this, ValueProperty)?.UpdateTarget();    }    private string ComputeDisplayName()    {        string text = this.PropertyDescriptor.DisplayName;        var disPlayNameAttribute = this.PropertyDescriptor.Attributes.Cast<Attribute>()                                          .Where(att => att is DisplayNameAttribute)                                          .Select(t => (DisplayNameAttribute)t)                                          .FirstOrDefault();        if (disPlayNameAttribute != null)        {            text = disPlayNameAttribute.DisplayName;        }        else        {            var displayName = this.PropertyDescriptor.GetAttribute<DisplayAttribute>()?.GetName();            if (!string.IsNullOrEmpty(displayName))            {                text = displayName;            }        }        var attribute2 = this.PropertyDescriptor.GetAttribute<ParenthesizePropertyNameAttribute>();        if (attribute2 != null && attribute2.NeedParenthesis)        {            text = "(" + text + ")";        }        return text;    }    internal int ComputeDisplayOrderInternal(bool isPropertyGridCategorized)    {        return ComputeDisplayOrder(isPropertyGridCategorized);    }    internal string ComputeCategoryForItem(PropertyDescriptor propertyDescriptor)    {        if (propertyDescriptor != null)        {            string? groupName = propertyDescriptor.GetAttribute<DisplayAttribute>()?.GetGroupName();            if (!string.IsNullOrEmpty(groupName))            {                return groupName;            }            var categoryAttribute = propertyDescriptor.GetAttribute<LocalizedCategoryAttribute>();            if (categoryAttribute != null)            {                return categoryAttribute.LocalizedCategory;            }            return propertyDescriptor.Category;        }        return string.Empty;    }    internal string ComputeCategoryValueForItem(PropertyDescriptor propertyDescriptor)    {        if (propertyDescriptor != null)        {            var attribute = propertyDescriptor.GetAttribute<LocalizedCategoryAttribute>();            if (attribute != null)            {                return attribute.CategoryValue;            }            return propertyDescriptor.Category;        }        return string.Empty;    }    internal string ComputeDescriptionForItem(PropertyDescriptor? propertyDescriptor)    {        if (propertyDescriptor != null)        {            var description = propertyDescriptor.GetAttribute<DisplayAttribute>()?.GetDescription();            if (!string.IsNullOrEmpty(description))            {                return description;            }            var descriptionAttr = propertyDescriptor.GetAttribute<DescriptionAttribute>();            if (descriptionAttr != null)            {                return descriptionAttr.Description;            }            return propertyDescriptor.Description;        }        return string.Empty;    }    internal IList<Type>? ComputeNewItemTypesForItem(PropertyDescriptor? propertyDescriptor)    {        return propertyDescriptor?.GetAttribute<NewItemTypesAttribute>()?.Types;    }    internal object? ComputeDefinitionKeyForItem(PropertyDescriptor? propertyDescriptor)    {        return propertyDescriptor?.GetAttribute<DefinitionKeyAttribute>()?.Key;    }    internal IList<string>? ComputeDependsOnPropertyItems(PropertyDescriptor? propertyDescriptor)    {        return propertyDescriptor?.GetAttribute<Attributes.DependsOnAttribute>()?.PropertyItemNames;    }    internal int? ComputeDisplayOrderForItem(PropertyDescriptor? propertyDescriptor)    {        var attribute = this.PropertyDescriptor.GetAttribute<DisplayAttribute>();        if (attribute != null && attribute.GetOrder().HasValue)        {            return attribute.GetOrder();        }        var list = propertyDescriptor?.Attributes.OfType<PropertyOrderAttribute>().ToList();        if (list != null && list.Count > 0)        {            this.ValidatePropertyOrderAttributes(list);            if (IsPropertyGridCategorized)            {                var propertyOrderAttribute = list.FirstOrDefault(x => x.UsageContext == UsageContextEnum.Categorized || x.UsageContext == UsageContextEnum.Both);                if (propertyOrderAttribute != null)                {                    return propertyOrderAttribute.Order;                }            }            else            {                var propertyOrderAttribute2 = list.FirstOrDefault(x => x.UsageContext == UsageContextEnum.Alphabetical || x.UsageContext == UsageContextEnum.Both);                if (propertyOrderAttribute2 != null)                {                    return propertyOrderAttribute2.Order;                }            }        }        return int.MaxValue;    }    internal bool ComputeExpandableAttributeForItem(PropertyDescriptor? propertyDescriptor)    {        return propertyDescriptor?.GetAttribute<ExpandableObjectAttribute>() != null;    }    internal object? ComputeDefaultValueAttributeForItem(PropertyDescriptor? propertyDescriptor)    {        return propertyDescriptor?.GetAttribute<DefaultValueAttribute>()?.Value;    }    internal object GetValueInstance(object sourceObject)    {        if (sourceObject is ICustomTypeDescriptor customTypeDescriptor)        {            sourceObject = customTypeDescriptor.GetPropertyOwner(PropertyDescriptor);        }        return sourceObject;    }    internal void RaiseContainerHelperInvalidated()    {        if (this.ContainerHelperInvalidated != null)        {            this.ContainerHelperInvalidated(this, EventArgs.Empty);        }    }    internal void UpdateAdvanceOptionsForItem(DependencyObject dependencyObject, DependencyPropertyDescriptor dpDescriptor, out object tooltip)    {        tooltip = StringConstants.Default;        bool flag = false;        bool num = typeof(Style).IsAssignableFrom(PropertyType);        flag = typeof(DynamicResourceExtension).IsAssignableFrom(PropertyType);        if (num || flag)        {            tooltip = StringConstants.Resource;        }        else if (dependencyObject != null && dpDescriptor != null)        {            if (BindingOperations.GetBindingExpressionBase(dependencyObject, dpDescriptor.DependencyProperty) != null)            {                tooltip = StringConstants.Databinding;                return;            }            switch (DependencyPropertyHelper.GetValueSource(dependencyObject, dpDescriptor.DependencyProperty).BaseValueSource)            {                case BaseValueSource.Inherited:                case BaseValueSource.DefaultStyle:                case BaseValueSource.ImplicitStyleReference:                    tooltip = StringConstants.Inheritance;                    break;                case BaseValueSource.Style:                    tooltip = StringConstants.StyleSetter;                    break;                case BaseValueSource.Local:                    tooltip = StringConstants.Local;                    break;                case BaseValueSource.DefaultStyleTrigger:                case BaseValueSource.TemplateTrigger:                case BaseValueSource.StyleTrigger:                case BaseValueSource.ParentTemplate:                case BaseValueSource.ParentTemplateTrigger:                    break;            }        }        else        {            if (object.Equals(Value, DefaultValue))            {                return;            }            if (DefaultValue != null)            {                tooltip = StringConstants.Local;            }            else if (PropertyType.IsValueType)            {                object objB = Activator.CreateInstance(PropertyType);                if (!object.Equals(Value, objB))                {                    tooltip = StringConstants.Local;                }            }            else if (Value != null)            {                tooltip = StringConstants.Local;            }        }    }    internal void UpdateAdvanceOptions()    {        this.AdvancedOptionsTooltip = ComputeAdvancedOptionsTooltip();    }    internal void UpdateIsExpandable()    {        this.IsExpandable = ComputeIsExpandable() && (ExpandableAttribute || ExpandableProperty);    }    internal void UpdateValueFromSource()    {        BindingOperations.GetBindingExpressionBase(this, ValueProperty)?.UpdateTarget();    }    private void ValidatePropertyOrderAttributes(List<PropertyOrderAttribute> list)    {        if (list.Count > 0 && list.FirstOrDefault(x => x.UsageContext == UsageContextEnum.Both) != null)        {            _ = list.Count;            _ = 1;        }    }    private bool CanExpandFromCollection()    {        if (PropertyType.IsGenericType && PropertyType.GetGenericTypeDefinition() != typeof(Dictionary<,>) && PropertyType.GetGenericTypeDefinition() != typeof(KeyValuePair<,>))        {            var type = PropertyType.GetGenericArguments().FirstOrDefault();            if (type != null && !type.IsPrimitive && !type.Equals(typeof(string)))            {                return !type.IsEnum;            }            return false;        }        if (!PropertyType.IsPrimitive && !PropertyType.Equals(typeof(string)))        {            return !PropertyType.IsEnum;        }        return false;    }    private static void ExecuteResetValueCommand(object sender, ExecutedRoutedEventArgs e)    {        var propertyItem = e.Parameter as PropertyItem;        if (propertyItem == null)        {            propertyItem = sender as PropertyItem;        }        if (propertyItem != null &&            propertyItem.DescriptorDefinition != null &&            propertyItem.DescriptorDefinition.ComputeCanResetValue())        {            propertyItem.DescriptorDefinition.ResetValue();        }    }    private static void CanExecuteResetValueCommand(object sender, CanExecuteRoutedEventArgs e)    {        var propertyItem = e.Parameter as PropertyItem;        if (propertyItem == null)        {            propertyItem = sender as PropertyItem;        }        e.CanExecute = propertyItem != null &&                       propertyItem.DescriptorDefinition != null &&                       propertyItem.DescriptorDefinition.ComputeCanResetValue();    }    private static void OnValueChanged(DependencyObject o, DependencyPropertyChangedEventArgs e)    {        ((DescriptorPropertyDefinitionBase)o).OnValueChanged(e.OldValue, e.NewValue);    }    private static void ExecuteCopyValueCommand(object sender, ExecutedRoutedEventArgs e)    {        var propertyItem = e.Parameter as PropertyItem;        if (propertyItem == null)        {            propertyItem = sender as PropertyItem;        }        if (propertyItem != null &&            propertyItem.DescriptorDefinition != null &&            propertyItem.DescriptorDefinition.ComputeCanCopyValue())        {            var value = propertyItem.Value;            // 1. 处理空值            if (value == null)            {                Clipboard.SetText(string.Empty);                return;            }            // 2. 获取对象的原始字符串表示（适配所有类型）            string clipboardText = value switch            {                // 字符串类型：直接使用原始值（避免额外引号）                string str => str,                // 基元类型（int/long/bool/double等）：直接转换为字符串                bool b => b.ToString().ToLower(), // 布尔值统一为小写（true/false）                char c => c.ToString(),                ValueType _ => value.ToString()!, // 所有值类型（结构体/基元）                // 其他引用类型（Object）：使用ToString()（若未重写则显示类型名）                _ => value.ToString() ?? string.Empty            };            // 3. 写入剪贴板            Clipboard.SetText(clipboardText);        }    }    private static void CanExecuteCopyValueCommand(object sender, CanExecuteRoutedEventArgs e)    {        var propertyItem = e.Parameter as PropertyItem;        if (propertyItem == null)        {            propertyItem = sender as PropertyItem;        }        e.CanExecute = propertyItem != null &&                       propertyItem.DescriptorDefinition != null &&                       propertyItem.DescriptorDefinition.ComputeCanCopyValue();    }}